fun solve(nums: Array<Long>, digit: Long): Long {
    var count: Long = 0
    val targetDigitChar = digit.toString()[0]

    for (num in nums) {
        var currentNum = num
        if (currentNum == 0L && digit == 0L) {
            count++
            continue
        }

        // Handle the case where the number is 0, but we already checked for digit 0 above
        if (currentNum == 0L) {
            continue
        }

        // Convert number to string for easier digit counting
        val numStr = currentNum.toString()
        var digitCountInNum: Long = 0
        for (char in numStr) {
            if (char == targetDigitChar) {
                digitCountInNum++
            }
        }
        count += digitCountInNum
    }

    return count
}
